#!/usr/bin/env pwshDescribe 'Detect Tool Integration Tests' {    BeforeAll {        $script:root = $PSScriptRoot | Split-Path -Parent | Split-Path -Parent        $script:detectTool = Join-Path $script:root 'scripts\utilities\detect-tool.ps1'        $script:tempRoot = Join-Path $script:root 'tmp-detect-tool-integration-tests'        $script:originalGentleVanguardBaseDir = $env:GENTLE_VANGUARD_BASE_DIR        $script:originalOpenCodeUser = $env:OPENCODE_SERVER_USERNAME        $script:originalClaudeVersion = $env:CLAUDE_VSCODE_VERSION        $script:originalUserProfile = $env:USERPROFILE    }    BeforeEach {        if (Test-Path $script:tempRoot) {            Remove-Item -Path $script:tempRoot -Recurse -Force -ErrorAction SilentlyContinue        }        New-Item -ItemType Directory -Path (Join-Path $script:tempRoot 'config') -Force | Out-Null        $env:GENTLE_VANGUARD_BASE_DIR = $script:tempRoot        Remove-Item Env:OPENCODE_SERVER_USERNAME -ErrorAction SilentlyContinue        Remove-Item Env:CLAUDE_VSCODE_VERSION -ErrorAction SilentlyContinue        $env:USERPROFILE = $script:tempRoot    }    AfterEach {        if ($null -eq $script:originalGentleVanguardBaseDir) {            Remove-Item Env:GENTLE_VANGUARD_BASE_DIR -ErrorAction SilentlyContinue        } else {            $env:GENTLE_VANGUARD_BASE_DIR = $script:originalGentleVanguardBaseDir        }        if ($null -eq $script:originalOpenCodeUser) {            Remove-Item Env:OPENCODE_SERVER_USERNAME -ErrorAction SilentlyContinue        } else {            $env:OPENCODE_SERVER_USERNAME = $script:originalOpenCodeUser        }        if ($null -eq $script:originalClaudeVersion) {            Remove-Item Env:CLAUDE_VSCODE_VERSION -ErrorAction SilentlyContinue        } else {            $env:CLAUDE_VSCODE_VERSION = $script:originalClaudeVersion        }        if ($null -eq $script:originalUserProfile) {            Remove-Item Env:USERPROFILE -ErrorAction SilentlyContinue        } else {            $env:USERPROFILE = $script:originalUserProfile        }        if (Test-Path $script:tempRoot) {            Remove-Item -Path $script:tempRoot -Recurse -Force -ErrorAction SilentlyContinue        }    }    function Invoke-DetectToolJson {        param([string]$ConfigPath = '')        $result = if ($ConfigPath) {            & $script:detectTool -AsJson -ConfigPath $ConfigPath        } else {            & $script:detectTool -AsJson        }        return ($result | ConvertFrom-Json)    }    It 'detects opencode from environment variables with highest confidence' {        $env:OPENCODE_SERVER_USERNAME = 'gentle-vanguard-user'        $result = Invoke-DetectToolJson        $result.name | Should -Be 'opencode'        $result.source | Should -Be 'env:OPENCODE_SERVER_USERNAME'        $result.isOpenCode | Should -Be $true        $result.confidence | Should -Be 100        $result.instructions.sessionAutostart | Should -Match 'session-autostart.cmd'    }    It 'detects claude-code from extension environment variable' {        $env:CLAUDE_VSCODE_VERSION = '1.0.0'        $result = Invoke-DetectToolJson        $result.name | Should -Be 'claude-code'        $result.isClaude | Should -Be $true        $result.configFile | Should -Be '.claude/settings.json'        $result.promptFile | Should -Be 'CLAUDE.md'    }    It 'detects opencode from repo marker directory when env vars are absent' {        New-Item -ItemType Directory -Path (Join-Path $script:tempRoot '.opencode') -Force | Out-Null        $result = Invoke-DetectToolJson        $result.name | Should -Be 'opencode'        $result.source | Should -Be 'dir:.opencode'        $result.confidence | Should -Be 85    }    It 'detects cline from marker file' {        New-Item -ItemType File -Path (Join-Path $script:tempRoot '.clinerules') -Force | Out-Null        $result = Invoke-DetectToolJson        $result.name | Should -Be 'cline'        $result.isCline | Should -Be $true        $result.promptFile | Should -Be '.clinerules'    }    It 'detects cursor from marker file' {        New-Item -ItemType File -Path (Join-Path $script:tempRoot '.cursorrules') -Force | Out-Null        $result = Invoke-DetectToolJson        $result.name | Should -Be 'cursor'        $result.isCursor | Should -Be $true        $result.promptFile | Should -Be '.cursorrules'    }    It 'detects windsurf from marker directory' {        New-Item -ItemType Directory -Path (Join-Path $script:tempRoot '.windsurf') -Force | Out-Null        $result = Invoke-DetectToolJson        $result.name | Should -Be 'windsurf'        $result.isWindsurf | Should -Be $true        $result.configFile | Should -Be '.windsurf/config.json'    }    It 'detects continue-dev from USERPROFILE config' {        New-Item -ItemType Directory -Path (Join-Path $script:tempRoot '.continue') -Force | Out-Null        '{}' | Set-Content -Path (Join-Path $script:tempRoot '.continue\config.json') -Encoding UTF8        $result = Invoke-DetectToolJson        $result.name | Should -Be 'continue-dev'        $result.isContinueDev | Should -Be $true        $result.source | Should -Match '\.continue\\config.json$'    }    It 'falls back to generic CLAUDE prompt detection and merges tool profile overrides' {        New-Item -ItemType File -Path (Join-Path $script:tempRoot 'CLAUDE.md') -Force | Out-Null        $configPath = Join-Path $script:tempRoot 'config\tool-config.json'        @'{  "toolProfiles": {    "claude-generic": {      "responseProfile": "compact",      "communicationLang": "en"    }  }}'@ | Set-Content -Path $configPath -Encoding UTF8        $result = Invoke-DetectToolJson -ConfigPath $configPath        $result.name | Should -Be 'claude-generic'        $result.promptFile | Should -Be 'CLAUDE.md'        $result.instructions.responseProfile | Should -Be 'compact'        $result.instructions.communicationLang | Should -Be 'en'    }    It 'returns unknown when no markers or env vars are present' {        $result = Invoke-DetectToolJson        $result.name | Should -Be 'unknown'        $result.confidence | Should -Be 0        $result.os.isWindows | Should -Be $true        $result.instructions.primaryEntryPoint | Should -Be 'docs/AGENTS.md'    }}


